export const getGetNoteFilesUrl = (params: GetNoteFilesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/note-files?${stringifiedParams}`
    : `/api/note-files`;
};

export const getNoteFiles = async (
  params: GetNoteFilesParams,
  options?: RequestInit,
): Promise<NoteFile[]> => {
  return customFetch<NoteFile[]>(getGetNoteFilesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetNoteFilesQueryKey = (params?: GetNoteFilesParams) => {
  return [`/api/note-files`, ...(params ? [params] : [])] as const;
};

export const getGetNoteFilesQueryOptions = <
  TData = Awaited<ReturnType<typeof getNoteFiles>>,
  TError = ErrorType<unknown>,
>(
  params: GetNoteFilesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getNoteFiles>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetNoteFilesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getNoteFiles>>> = ({
    signal,
  }) => getNoteFiles(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getNoteFiles>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

